// --- Sync Manager (higher-level orchestration) ---

/// Coordinates periodic and on-demand data synchronization.
class SyncManager {
  final ApiClient _apiClient;
  DateTime? _lastSyncedAt;
  Timer? _periodicTimer;
  bool _isSyncing = false;

  /// Stream controller that emits sync results for UI consumption.
  final StreamController<SyncResult> _syncResultController =
      StreamController<SyncResult>.broadcast();

  Stream<SyncResult> get syncResults => _syncResultController.stream;

  SyncManager({required ApiClient apiClient}) : _apiClient = apiClient;

  /// Start periodic background sync.
  void startPeriodicSync({Duration interval = const Duration(minutes: 5)}) {
    _periodicTimer?.cancel();
    _periodicTimer = Timer.periodic(interval, (_) => sync());
  }

  /// Stop periodic background sync.
  void stopPeriodicSync() {
    _periodicTimer?.cancel();
    _periodicTimer = null;
  }

  /// Perform a sync now. Returns the result or null if a sync is already
  /// in progress.
  Future<SyncResult?> sync({
    List<Map<String, dynamic>> localChanges = const [],
  }) async {
    if (_isSyncing) {
      debugPrint('[SyncManager] Sync already in progress, skipping.');
      return null;
    }

    _isSyncing = true;
    try {
      final since = _lastSyncedAt ?? DateTime.fromMillisecondsSinceEpoch(0);

      final result = await _apiClient.syncData(
        lastSyncedAt: since,
        localChanges: localChanges,
      );

      _lastSyncedAt = result.syncedAt;
      _syncResultController.add(result);

      debugPrint(
        '[SyncManager] Sync complete: '
        '↑${result.uploadedCount} ↓${result.downloadedCount} '
        'conflicts=${result.conflicts.length}',
      );

      return result;
    } catch (e) {
      debugPrint('[SyncManager] Sync failed: $e');
      rethrow;
    } finally {
      _isSyncing = false;
    }
  }

  void dispose() {
    stopPeriodicSync();
    _syncResultController.close();
  }
}

// --- Example Usage (main) ---

Future<void> main() async {
  // Create the API client with certificate pinning for the production host.
  final apiClient = ApiClient(
    pinConfig: const CertificatePinningConfig(
      pinnedHosts: {
        'api.example.com': [
          'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=',
          'BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=',
        ],
      },
    ),
  );

  try {
    // --- Authentication ---
    debugPrint('Logging in...');
    final tokens = await apiClient.login(
      email: 'user@example.com',
      password: 'securePassword123',
    );
    debugPrint('Logged in. Token expires at: ${tokens.expiresAt}');

    // --- User Profile ---
    debugPrint('Fetching profile...');
    final profile = await apiClient.getProfile();
    debugPrint('Hello, ${profile.displayName} (${profile.email})');

    debugPrint('Updating profile...');
    final updatedProfile = await apiClient.updateProfile(
      displayName: 'New Display Name',
    );
    debugPrint('Updated name: ${updatedProfile.displayName}');

    // --- Data Synchronization ---
    final syncManager = SyncManager(apiClient: apiClient);

    // Listen to sync results.
    syncManager.syncResults.listen((result) {
      debugPrint(
        'Sync event: ↑${result.uploadedCount} ↓${result.downloadedCount}',
      );
    });

    // Manual sync with local changes.
    debugPrint('Syncing data...');
    final syncResult = await syncManager.sync(
      localChanges: [
        {
          'type': 'update',
          'resource': 'note',
          'id': 'note-123',
          'data': {'title': 'Updated note', 'body': 'New content'},
          'timestamp': DateTime.now().toIso8601String(),
        },
      ],
    );
    if (syncResult != null) {
      debugPrint(
        'Sync done: uploaded=${syncResult.uploadedCount}, '
        'downloaded=${syncResult.downloadedCount}',
      );
    }

    // Start periodic sync every 5 minutes.
    syncManager.startPeriodicSync();

    // ... app runs ...

    // Cleanup.
    syncManager.dispose();

    // --- Logout ---
    debugPrint('Logging out...');
    await apiClient.logout();
    debugPrint('Logged out.');
  } on AuthenticationException catch (e) {
    debugPrint('Auth error: ${e.message}');
  } on ApiException catch (e) {
    debugPrint('API error [${e.statusCode}]: ${e.message}');
  } on NetworkException catch (e) {
    debugPrint('Network error: ${e.message}');
  } finally {
    apiClient.dispose();
  }
